import ipaddress

iocs = inputs.get('iocs', [])
intel_results = []
seen = set()

def is_public_ip(value):
    try:
        ip_obj = ipaddress.ip_address(value)
    except Exception:
        return False
    return not (
        ip_obj.is_private or ip_obj.is_loopback or ip_obj.is_reserved
        or ip_obj.is_link_local or ip_obj.is_multicast or ip_obj.is_unspecified
    )

for ioc in iocs:
    ioc_type = ioc.get('type', '')
    ioc_value = str(ioc.get('value', '')).strip()
    key = (ioc_type, ioc_value)

    if not ioc_value or key in seen:
        continue
    seen.add(key)

    if ioc_type == 'ip':
        if not is_public_ip(ioc_value):
            continue
        result = tool.run_safe('threatbook_ip_query', ip=ioc_value)
        if result['success']:
            intel_results.append({'source': 'threatbook', 'type': 'ip',
                                   'value': ioc_value, 'result': result['text']})

    elif ioc_type == 'domain':
        result = tool.run_safe('threatbook_domain_query', domain=ioc_value)
        if result['success']:
            intel_results.append({'source': 'threatbook', 'type': 'domain',
                                   'value': ioc_value, 'result': result['text']})

    elif ioc_type == 'url':
        result = tool.run_safe('threatbook_url_query', url=ioc_value)
        if result['success']:
            intel_results.append({'source': 'threatbook', 'type': 'url',
                                   'value': ioc_value, 'result': result['text']})

outputs['intel_results'] = intel_results
outputs['has_intel'] = len(intel_results) > 0

import json

parsed_alert = inputs.get('parsed_alert', {})
vuln_id = parsed_alert.get('vuln_id', '')
vuln_info = {}

if vuln_id:
    result = tool.run_safe('__mcp_vuln_query', vuln_id=vuln_id)
    if result['success']:
        try:
            obj = result.get('obj')
            if isinstance(obj, str):
                obj = json.loads(obj)
            vuln_info = obj if isinstance(obj, dict) else {}
        except Exception:
            vuln_info = {'raw_result': result.get('text', '')}
    else:
        vuln_info = {'error': result.get('error', 'Query failed'), 'vuln_id': vuln_id}

outputs['vuln_info'] = vuln_info
outputs['has_vuln_info'] = bool(vuln_info) and 'error' not in vuln_info
